node -e "const fs=require('fs'); fs.writeFileSync('scripts/build.js', 'import { mkdirSync, readFileSync, writeFileSync } from 'node:fs';

const config = JSON.parse(readFileSync('build.config.json', 'utf8'));
const entryPath = config.entry ?? config.input;
if (!entryPath) throw new Error('build.config.json must define entry');
const source = readFileSync(entryPath, 'utf8').trim();
mkdirSync('dist', { recursive: true });
writeFileSync('dist/manifest.json', JSON.stringify({ entry: entryPath, bytes: source.length, upper: source.toUpperCase() }, null, 2) + '\n');
');"
